const items = $input.all();
const out = [];
for (const i of items) {
  const e = i.json || {};
  const exec = e.execution || {};
  const wf = e.workflow || {};
  const err = exec.error || {};
  const node = err.node || {};
  const nodeName = node.name
    || err.context?.nodeName
    || exec.lastNodeExecuted
    || (err.message?.match(/^([^:]+):/) || [])[1]
    || 'Unknown';
  out.push({ json: {
    workflow_name: wf.name || 'Unknown',
    workflow_id: wf.id || 'Unknown',
    execution_id: exec.id || 'Unknown',
    node_name: nodeName,
    node_type: node.type || 'Unknown',
    error_message: err.message || 'No message',
    error_stack: (err.stack || '').toString().slice(0, 500),
    timestamp: new Date().toISOString()
  }});
}
return out;

